INSERT INTO Notifications VALUES(29,'task','系统提醒','2024-03-04 10:00:00','绩效考核提醒','距离绩效考核截止还有6天，请尽快完成自评。','绩效考核进度提醒：\n\n考核周期：Q1 2024\n当前阶段：员工自评\n截止日期：2024-03-10\n剩余时间：6天\n\n您的自评尚未提交，请登录绩效考核系统尽快完成。',0,'Assignment','warning',1,'2024-03-04 10:00:00',NULL);
INSERT INTO Notifications VALUES(30,'system','会议助手','2024-03-05 15:30:00','会议提醒：技术分享会','明天的微服务架构技术分享会将在培训室举行，请准时参加。','会议详情：\n\n主题：微服务架构技术分享\n主讲人：张三\n时间：2024-03-06 15:00-16:30\n地点：培训室\n\n欢迎大家准时参加，可自带笔记。',0,'Event','primary',1,'2024-03-05 15:30:00',NULL);
INSERT INTO Notifications VALUES(31,'message','王经理','2024-03-07 09:00:00','季度汇报材料收集','王经理：请各组长在3月12日前提交季度汇报PPT。','王经理 发送于 2024-03-07 09:00\n\n请各组长在3月12日前提交季度汇报PPT，内容包括：\n1. 本季度工作成果\n2. 关键指标完成情况\n3. 遇到的问题及解决方案\n4. 下季度工作计划\n\n汇报会暂定于3月15日举行。',1,'Chat','secondary',1,'2024-03-07 09:00:00',NULL);
INSERT INTO Notifications VALUES(32,'system','人事系统','2024-03-08 11:00:00','三八妇女节福利','公司为全体女员工准备了节日礼物，请到前台领取。','三八妇女节福利通知：\n\n为庆祝三八妇女节，公司为全体女员工准备了以下福利：\n1. 节日鲜花一束\n2. 精美礼品一份\n3. 下午茶券一张\n\n领取地点：一楼前台\n领取时间：2024-03-08 09:00-17:00',0,'Event','success',1,'2024-03-08 11:00:00',NULL);
INSERT INTO Notifications VALUES(33,'task','赵六','2024-03-11 14:00:00','代码审查通知','您提交的CRM系统代码需要审查，请关注审查意见。','代码审查通知：\n\n项目：CRM系统\n提交模块：客户管理\n提交时间：2024-03-10\n审查人：赵六\n\n请登录代码审查平台查看详细意见并回复。',0,'Assignment','primary',1,'2024-03-11 14:00:00',NULL);
INSERT INTO Notifications VALUES(34,'system','安全中心','2024-03-12 16:00:00','钓鱼邮件预警','近日发现有冒充IT部门的钓鱼邮件，请提高警惕。','安全预警通知：\n\n近日发现有冒充IT部门的钓鱼邮件发送至公司邮箱，特征如下：\n1. 发件人伪装为 IT Support\n2. 要求点击链接修改密码\n3. 链接指向仿冒登录页面\n\n请不要点击可疑链接，如有疑问请联系IT安全部门确认。',0,'SystemUpdate','error',1,'2024-03-12 16:00:00',NULL);
INSERT INTO Notifications VALUES(35,'message','李四','2024-03-13 10:30:00','数据库脚本分享','李四：分享一个批量数据清洗的SQL脚本，很实用。','李四 发送于 2024-03-13 10:30\n\n分享一个实用的SQL脚本，用于批量清洗重复数据：\n\n```sql\nWITH CTE AS (\n    SELECT *,\n        ROW_NUMBER() OVER (PARTITION BY col1, col2 ORDER BY id) AS rn\n    FROM table_name\n)\nDELETE FROM CTE WHERE rn > 1;\n```\n\n这个脚本可以快速去除表中的重复记录，亲测有效！',1,'Chat','secondary',1,'2024-03-13 10:30:00',NULL);
INSERT INTO Notifications VALUES(36,'system','行政部','2024-03-14 09:00:00','办公室搬迁通知','技术部将于3月18日搬迁至新办公区B座5层。','办公室搬迁通知：\n\n搬迁时间：2024-03-18\n原办公区：A座3层\n新办公区：B座5层\n\n注意事项：\n1. 请提前整理个人物品\n2. 重要文件请自行保管\n3. 搬迁期间IT将协助网络配置\n4. 新办公区配有咖啡机和休息区',0,'Event','info',1,'2024-03-14 09:00:00',NULL);
